153→+    private List<SpaceNodeTreeNode> filterAndConvertFolders(List<TreeNode<SpaceNodeVo>> nodes) {
154→+        if (nodes == null || nodes.isEmpty()) {
155→+            return List.of();
156→+        }
157→+        List<SpaceNodeTreeNode> result = new ArrayList<>();
158→+        for (TreeNode<SpaceNodeVo> node : nodes) {
159→+            SpaceNodeVo data = node.getData();
160→+            if (Objects.equals(data.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
161→+                List<SpaceNodeTreeNode> childFolders = filterAndConvertFolders(node.getChildren());
162→+                SpaceNodeTreeNode grpcNode = SpaceNodeTreeNode.newBuilder()
163→+                        .setId(data.getId())
164→+                        .setName(data.getName() != null ? data.getName() : "")
165→+                        .setType(data.getType())
166→+                        .setParentId(node.getParentId() != null ? node.getParentId() : 0L)
167→+                        .setAppSpaceNodeId(data.getAppSpaceNodeId() != null ? data.getAppSpaceNodeId() : "")
168→+                        .setDescription(data.getDescription() != null ? data.getDescription() : "")
169→+                        .addAllChildren(childFolders)
170→+                        .build();
171→+                result.add(grpcNode);
172→+            } else {
173→+                List<SpaceNodeTreeNode> childFolders = filterAndConvertFolders(node.getChildren());
174→+                result.addAll(childFolders);
175→+            }
176→+        }
177→+        return result;
178→+    }
