 97→    @RabbitListener(queues = SPACE_NODE_MIGRATION_QUEUE)
 98→    public void handle(Message message, Channel channel) throws IOException {
 99→        String body = new String(message.getBody());
100→        log.info("Received space node migration task message: {}", body);
101→
102→        SpaceNodeMigrationMessage messageDto = JSONUtil.toBean(body, SpaceNodeMigrationMessage.class);
103→        String taskId = messageDto.getTaskId();
104→
105→        try {
106→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
107→            ExceptionUtil.isNotNull(task, DatabaseException.QUERY_EMPTY_BY_ID);
108→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.PROCESSING.getValue());
109→            spaceNodeMigrationTaskService.updateById(task);
110→
111→            executeTask(task);
112→
113→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.COMPLETED.getValue());
114→            spaceNodeMigrationTaskService.updateById(task);
115→
116→        } catch (Exception e) {
117→            log.error("Failed to process space node migration task: taskId={}, error={}", taskId, e.getMessage(), e);
118→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
119→            if (task != null) {
120→                task.setStatus(SpaceNodeMigrationTaskStatusEnum.FAILED.getValue());
121→                task.setErrorMessage(e.getMessage());
122→                spaceNodeMigrationTaskService.updateById(task);
123→            }
124→        } finally {
125→            // 先不考虑重试
126→            long deliveryTag = message.getMessageProperties().getDeliveryTag();
127→            channel.basicAck(deliveryTag, false);
128→        }
129→    }
