131→    private void executeTask(SpaceNodeMigrationTaskEntity task) throws IOException {
132→        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(task.getEmail());
133→        ExceptionUtil.isNotNull(user, SpaceNodeMigrationException.OPERATOR_NOT_EXIST);
134→        Long userId = user.getId();
135→        // 鉴权
136→        if (!spaceQueryManager.isUserSpaceAdmin(userId, task.getTargetSpaceId())) {
137→            throw new BusinessException(AuthException.UNAUTHORIZED);
138→        }
139→
140→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = deserializeTree(task.getOriginTree());
141→        List<SpaceAppRelVo> sourceSpaceAppRels = JSONUtil.toList(task.getSourceSpaceAppRels(), SpaceAppRelVo.class);
142→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(task.getType());
143→
144→        log.info("executeTask: taskId={}, treeSize={}, type: {}, targetParentNodeId={}, appRels: {}",
145→                task.getTaskId(), spaceNodeTree.size(), migrationType.getDescription(), task.getTargetParentNodeId(), task.getSourceSpaceAppRels());
146→
147→        MigrationConfig migrationConfig = MigrationConfig.builder()
148→                .email(task.getEmail())
149→                .sourceSpaceAppRels(sourceSpaceAppRels)
150→                .build();
151→        
152→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
153→                spaceNodeTree, 
154→                task.getTargetSpaceId(),
155→                task.getSourceSpaceId(),
156→                migrationType, 
157→                migrationConfig
158→        );
159→        
160→        log.info("Overall migration completed: success={}, failed={}, total mappings={}", 
161→                overallResult.getSuccessCount(), overallResult.getFailedCount(), 
162→                overallResult.getNodeIdMapping().size());
163→
164→        // 迁移中遇到错误抛异常并终止迁移
165→        if (overallResult.getErrorMessage() != null) {
166→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
167→            throw new BusinessException(overallResult.getErrorMessage());
168→        }
169→
170→        // 迁移后的节点重新构建成树并入库
171→        // targetParentNodeId 是 space_node 表的 ID，需转换为 node 表的 ID 作为树的 parentId
172→        Long rootParentId = ROOT_PARENT_ID;
173→        if (task.getTargetParentNodeId() != null) {
174→            NodeEntity parentNode = nodeService.getByRelId(task.getTargetParentNodeId());
175→            if (parentNode != null) {
176→                rootParentId = parentNode.getId();
177→            } else {
178→                log.warn("targetParentNodeId={} 对应的 node 不存在，使用根目录", task.getTargetParentNodeId());
179→            }
180→        }
181→        saveNewNodeTree(spaceNodeTree, task.getTargetSpaceId(), overallResult.getNodeIdMapping(), userId, migrationType, rootParentId);
182→        // 判断是空间站内迁移并且保留状态是false，调用文件删除接口，把源文件删除
183→        if (!task.getIsRemained() && task.getType().equals(MigrationTypeEnum.INTRA_SERVER.getValue())) {
184→            for (TreeNode<SpaceNodeVo> treeNode : spaceNodeTree) {
185→                spaceNodeUpdateManager.deleteSpaceNode(treeNode.getRelId(), userId);
186→            }
187→        }
188→    }
189→
190→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping, Long userId, MigrationTypeEnum migrationType, Long rootParentId) {
191→        if (originalTree == null || originalTree.isEmpty()) {
192→            log.info("No tree nodes to save for space: {}", spaceId);
193→            return;
194→        }
195→
196→        log.info("Starting to save new node tree for space: {}, rootParentId: {}, total original nodes: {}", spaceId, rootParentId, originalTree.size());
197→
198→        for (TreeNode<SpaceNodeVo> node : originalTree) {
199→            saveNodeAndChildren(node, spaceId, nodeIdMapping, rootParentId, userId, migrationType);
200→        }
201→
202→        log.info("Completed saving new node tree for space: {}", spaceId);
203→    }
204→
205→    private String resolveUniqueName(String spaceId, String name, Long parentId) {
206→        if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, name, parentId)) {
207→            return name;
208→        }
209→        int count = 1;
210→        while (true) {
211→            String candidate = name + "(" + count + ")";
212→            if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, candidate, parentId)) {
213→                return candidate;
214→            }
215→            count++;
216→        }
217→    }
218→
219→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping, Long parentId, Long userId, MigrationTypeEnum migrationType) {
220→        SpaceNodeVo spaceNodeVo = node.getData();
221→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
222→        String newNodeId = nodeIdMapping.get(oldNodeId);
223→
224→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
225→            newNodeId = "";
226→        }
227→
228→        if (newNodeId == null) {
229→            log.error("No mapping found for node: {}", oldNodeId);
230→            return;
231→        }
232→
233→        String originalName = spaceNodeVo.getName();
234→        String name = MigrationTypeEnum.CROSS_SERVER.equals(migrationType)
235→                ? resolveUniqueName(spaceId, originalName, parentId)
236→                : originalName;
237→        if (!name.equals(originalName)) {
238→            log.info("[2010-change-filename] migrate node name conflict, renamed: [{}] -> [{}], spaceId: {}, " +
239→                            "parentId: {}",
240→                    originalName,
241→                    name, spaceId, parentId);
242→        }
243→
244→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
245→                .appSpaceNodeId(newNodeId)
246→                .name(name)
247→                .type(spaceNodeVo.getType())
248→                .description(spaceNodeVo.getDescription())
249→                .spaceId(spaceId)
250→                .createdBy(userId)
251→                .updatedBy(userId)
252→                .build();
253→
254→        spaceNodeService.save(spaceNodeEntity);
255→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
256→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
257→
258→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
259→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
260→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId, migrationType);
261→            }
262→        }
263→    }
264→
265→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
266→        ObjectMapper mapper = objectMapper.copy();
267→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
268→        SimpleModule module = new SimpleModule();
269→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
270→        mapper.registerModule(module);
271→        JavaType treeNodeType =
272→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
273→        JavaType listType =
274→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
275→        return mapper.readValue(json, listType);
276→    }
277→
278→}

