 93→    @Override
 94→    public List<VersionSnapshotVo> listVersionSnapshot(Long spaceNodeId, Integer status) {
 95→        List<CollabspaceVersionSnapshotEntity> list = versionSnapshotService.getByNodeId(spaceNodeId, status);
 96→        if (list.isEmpty()){
 97→            return new ArrayList<>();
 98→        }
 99→        List<Long> creatorList = new ArrayList<>(list.stream().map(CollabspaceVersionSnapshotEntity::getCreatedBy).toList());
100→        List<Long> operatorList = list.stream().map(CollabspaceVersionSnapshotEntity::getOperatorId).toList();
101→        if (!operatorList.isEmpty()){
102→            creatorList.addAll(operatorList);
103→        }
104→        creatorList = creatorList.stream().filter(o -> o != null && o != 0L).toList();
105→        List<UserSimpleInfoVo> userList = apitableGrpcClientService.getUserByIds(creatorList);
106→        List<VersionSnapshotVo> voList = new ArrayList<>();
107→        list.forEach(item -> {
108→            Long userId = item.getOperatorId();
109→            UserSimpleInfoVo operator = userList.stream().filter(o -> Objects.equals(o.getId(), userId)).findFirst().orElse(null);
110→            UserSimpleInfoVo creator = userList.stream().filter(o -> Objects.equals(o.getId(), item.getCreatedBy())).findFirst().orElse(null);
111→            String opUserName = operator == null ? "" : operator.getNickName();
112→            String createUserName = creator == null ? "" : creator.getNickName();
113→            String deleteTime = status.equals(VersionSnapshotStatusEnum.DISABLED.getValue()) ?
114→                    item.getUpdatedAt().toString() : "";
115→            voList.add(VersionSnapshotVo.builder().snapshotName(item.getSnapshotName()).id(item.getId().toString())
116→                    .snapshotId(item.getSnapshotId()).snapshotCreator(createUserName).
117→                    snapshotDeleteUser(opUserName).snapshotCreateTime(item.getCreatedAt().toString()).
118→                    snapshotDeleteTime(deleteTime).build());
119→        });
120→        List<VersionSnapshotVo> finalList = voList;
121→        finalList = finalList.stream().sorted(Comparator.comparing(VersionSnapshotVo::getSnapshotCreateTime)).toList();
122→        return finalList;
123→    }
