125→    private List<FolderTreeNodeVo> buildFolderTree(String spaceId) {
126→        List<TreeNode<SpaceNodeVo>> fullTree = spaceNodeQueryManager.getSpaceNodeTree(spaceId);
127→        return filterFolders(fullTree);
128→    }
129→
130→    private List<FolderTreeNodeVo> filterFolders(List<TreeNode<SpaceNodeVo>> nodes) {
131→        if (nodes == null || nodes.isEmpty()) {
132→            return List.of();
133→        }
134→        List<FolderTreeNodeVo> result = new ArrayList<>();
135→        for (TreeNode<SpaceNodeVo> node : nodes) {
136→            SpaceNodeVo data = node.getData();
137→            if (Objects.equals(data.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
138→                result.add(FolderTreeNodeVo.builder()
139→                        .id(data.getId())
140→                        .name(data.getName())
141→                        .children(filterFolders(node.getChildren()))
142→                        .build());
143→            } else {
144→                result.addAll(filterFolders(node.getChildren()));
145→            }
146→        }
147→        return result;
148→    }
