 99→    @Override
100→    public String createMigrationTask(List<Long> spaceNodeIds, String targetSpaceId, String sourceSpaceId, Long userId, Boolean isRemained, Long targetParentNodeId) {
101→        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
102→        String email = user.getEmail();
103→        Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
104→        // 为了尽量保持原 spaceNodeTree 的相对顺序, 直接拉整个树再筛选
105→        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
106→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
107→        List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream().map(SpaceAppRelVo::new).toList();
108→
109→        // 目前每个服务都只会执行一种迁移逻辑, MigrationTypeEnum直接由服务环境判断, mirror服务只执行跨服务器迁移, 其它的都是服务器内迁移
110→        String taskId;
111→        if (constProperties.isMirror()) {
112→            taskId = collabspaceGrpcClientService.createSpaceNodeMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps, targetParentNodeId);
113→        } else {
114→            taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
115→                    MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained, targetParentNodeId);
116→        }
117→
118→        log.info("createMigrationTask: taskId={}, sourceNodeIds={}, targetSpaceId={}, sourceSpaceId={}, userId={}, targetParentNodeId={}, filteredTreeSize={}",
119→                taskId, spaceNodeIds, targetSpaceId, sourceSpaceId, userId, targetParentNodeId, spaceNodeTree.size());
