127→        if (CollectionUtils.isEmpty(spaceNodeTree) || StringUtils.isBlank(targetSpaceId) || StringUtils.isBlank(email) || StringUtils.isBlank(sourceSpaceId)) {
128→            log.error("email={}, targetSpaceId={}, sourceSpaceId={}", email, targetSpaceId, sourceSpaceId);
129→            throw new BusinessException("acceptMigrationTask: empty or invalid arguments");
130→        }
131→
132→        String taskId = sourceSpaceId + "-" + targetSpaceId + "-" + System.currentTimeMillis();
133→
134→        SpaceNodeMigrationTaskEntity spaceNodeMigrationTaskEntity = SpaceNodeMigrationTaskEntity.builder()
135→                .taskId(taskId)
136→                .sourceSpaceId(sourceSpaceId)
137→                .targetSpaceId(targetSpaceId)
138→                .email(email)
139→                .originTree(JSONUtil.toJsonStr(spaceNodeTree))
140→                .sourceSpaceAppRels(JSONUtil.toJsonStr(appRels))
141→                .status(SpaceNodeMigrationTaskStatusEnum.PENDING.getValue())
142→                .type(migrationType)
143→                .isRemained(isRemained)
144→                .targetParentNodeId(targetParentNodeId)
145→                .build();
146→        spaceNodeMigrationTaskService.save(spaceNodeMigrationTaskEntity);
147→
148→        SpaceNodeMigrationMessage message = SpaceNodeMigrationMessage.builder()
149→                .taskId(taskId)
150→                .build();
151→        rabbitMqSender.directSend(SPACE_NODE_MIGRATION_EXCHANGE, SPACE_NODE_MIGRATION_KEY, JSONUtil.toJsonStr(message));
152→
153→        log.info("acceptMigrationTask: taskId={}, email={}, targetSpaceId={}, sourceSpaceId={}, targetParentNodeId={}, treeSize={}",
154→                taskId, email, targetSpaceId, sourceSpaceId, targetParentNodeId, spaceNodeTree.size());
