337→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping, Long userId) {
338→        if (originalTree == null || originalTree.isEmpty()) {
339→            log.info("No tree nodes to save for space: {}", spaceId);
340→            return;
341→        }
342→
343→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
344→
345→        for (TreeNode<SpaceNodeVo> node : originalTree) {
346→            Long parentId = ROOT_PARENT_ID;
347→            if (spaceId.equals(node.getData().getSpaceId())) {
348→                // 同空间站复制在原父节点下
349→                // todo 优化
350→                parentId = node.getParentId();
351→            }
352→            saveNodeAndChildren(node, spaceId, nodeIdMapping, parentId, userId);
353→        }
354→
355→        log.info("Completed saving new node tree for space: {}", spaceId);
356→    }
357→
358→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping, Long parentId, Long userId) {
359→        SpaceNodeVo spaceNodeVo = node.getData();
360→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
361→        String newNodeId = nodeIdMapping.get(oldNodeId);
362→
363→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
364→            newNodeId = "";
365→        }
366→
367→        if (newNodeId == null) {
368→            log.error("No mapping found for node: {}", oldNodeId);
369→            return;
370→        }
371→
372→        // todo:这里的序号没有考虑并发问题，如有需使用分布式锁
373→        Integer count = nodeInstancesManager.getCountByOriginId(node.getData().getId());
374→        String name = node.getData().getName() +  "的副本" ;
375→        if (count > 0){
376→            name = name + "(" + count + ")";
377→        }
378→
379→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
380→                .appSpaceNodeId(newNodeId)
381→                .name(name)
382→                .type(spaceNodeVo.getType())
383→                .description(spaceNodeVo.getDescription())
384→                .spaceId(spaceId)
385→                .createdBy(userId)
386→                .updatedBy(userId)
387→                .build();
388→
389→        spaceNodeService.save(spaceNodeEntity);
390→
391→        // 补充副本关系
392→        nodeInstancesManager.createInstance(node.getData().getId(), spaceNodeEntity.getId(), 0);
393→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
394→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
395→
396→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
397→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
398→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId);
399→            }
400→        }
401→    }
