696→    private List<SpaceNodeTreeNode> filterAndConvertFolders(List<TreeNode<SpaceNodeVo>> nodes) {
697→        if (nodes == null || nodes.isEmpty()) {
698→            return List.of();
699→        }
700→        List<SpaceNodeTreeNode> result = new ArrayList<>();
701→        for (TreeNode<SpaceNodeVo> node : nodes) {
702→            SpaceNodeVo data = node.getData();
703→            if (Objects.equals(data.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
704→                List<SpaceNodeTreeNode> childFolders = filterAndConvertFolders(node.getChildren());
705→                SpaceNodeTreeNode grpcNode = SpaceNodeTreeNode.newBuilder()
706→                        .setId(data.getId())
707→                        .setName(data.getName() != null ? data.getName() : "")
708→                        .setType(data.getType())
709→                        .setParentId(node.getParentId() != null ? node.getParentId() : 0L)
710→                        .setAppSpaceNodeId(data.getAppSpaceNodeId() != null ? data.getAppSpaceNodeId() : "")
711→                        .setDescription(data.getDescription() != null ? data.getDescription() : "")
712→                        .addAllChildren(childFolders)
713→                        .build();
714→                result.add(grpcNode);
715→            } else {
716→                List<SpaceNodeTreeNode> childFolders = filterAndConvertFolders(node.getChildren());
717→                result.addAll(childFolders);
718→            }
719→        }
720→        return result;
721→    }
