 87→    public List<TreeNode<SpaceNodeVo>> getSpaceNodeTree(String spaceId) {
 88→        long t0 = System.currentTimeMillis();
 89→
 90→        // 联表查询：一次 DB 同时取 space_node 数据 + node 树结构 + 锁定/分享标识
 91→        List<SpaceNodeWithNodeDto> combined = spaceNodeService.listBySpaceIdWithNodeInfo(spaceId, false);
 92→        long t1 = System.currentTimeMillis();
 93→        log.info("[2009-perf][getSpaceNodeTree] spaceId={} nodeCount={} listBySpaceIdJoinNode={}ms", spaceId, combined.size(), t1 - t0);
 94→
 95→        // 从 DTO 提取锁定/分享标识，按 id 索引
 96→        Map<Long, SpaceNodeWithNodeDto> dtoMap = new HashMap<>(combined.size());
 97→        List<SpaceNodeEntity> entities = new ArrayList<>(combined.size());
 98→        List<NodeEntity> nodeEntities = new ArrayList<>(combined.size());
 99→        for (SpaceNodeWithNodeDto dto : combined) {
100→            dtoMap.put(dto.getId(), dto);
101→            entities.add(dto);
102→            nodeEntities.add(dto.toNodeEntity());
103→        }
104→
105→        List<SpaceNodeVo> vos = spaceNodeTransfer.toSpaceNodeVoWithRole(entities);
106→        long t2 = System.currentTimeMillis();
107→        log.info("[2009-perf][getSpaceNodeTree] spaceId={} toSpaceNodeVoWithRole={}ms", spaceId, t2 - t1);
108→
109→        // 设置锁定/分享标识（已在主查询中一并获取，无额外 DB 调用）
110→        // 先清除 BeanUtils 复制的值，只设 true，null 不序列化
111→        for (SpaceNodeVo vo : vos) {
112→            vo.setIsLocked(null);
113→            vo.setHasShare(null);
114→            SpaceNodeWithNodeDto dto = dtoMap.get(vo.getId());
115→            if (dto == null) continue;
116→            // 锁定标识：仅管理员可见，且实际有锁时才设 true
117→            if (vo.getPermissions() != null && Boolean.TRUE.equals(vo.getPermissions().getManageable())
118→                    && Boolean.TRUE.equals(dto.getIsLocked())) {
119→                vo.setIsLocked(true);
120→            }
121→            // 分享标识：编辑者可见，且实际有分享时才设 true
122→            if (vo.getPermissions() != null && Boolean.TRUE.equals(vo.getPermissions().getEditable())
123→                    && Boolean.TRUE.equals(dto.getHasShare())) {
124→                vo.setHasShare(true);
125→            }
126→        }
127→
128→        // 使用预取的 nodeEntities，跳过 buildNodeTree 内部的 listByRelIds
129→        List<TreeNode<SpaceNodeVo>> result = treeNodeTemplate.buildNodeTree(vos, nodeEntities, ROOT_PARENT_ID);
130→        long t3 = System.currentTimeMillis();
131→        log.info("[2009-perf][getSpaceNodeTree] spaceId={} buildNodeTree={}ms total={}ms", spaceId, t3 - t2, t3 - t0);
132→
133→        return result;
134→    }
